		return;
	end
	State.IsResetting = true;
	Logger.log(LUAOBFUSACTOR_DECRYPT_STR_0("\178\80\9\106\218", "\142\224\21\90\47"), reason or LUAOBFUSACTOR_DECRYPT_STR_0("\85\225\19\121\228\185\160\71\241\19", "\229\20\180\71\54\196\235"));
