	end
	task.wait(1);
	State.IsResetting = false;
	Logger.log(LUAOBFUSACTOR_DECRYPT_STR_0("\105\117\134", "\76\58\44\213\142\177"), LUAOBFUSACTOR_DECRYPT_STR_0("\249\1\33\29\89\252\10\55\9", "\24\171\68\114\77"));
